"use client";

import { useEffect, useMemo, useRef, useState } from "react";
import { MessageCircle, Send, X } from "lucide-react";

type GuidanceResponse = {
  disease: string;
  prescription: string;
  llmGuidance: {
    summary: string;
    domesticRemedies: string[];
    precautions: string[];
    whenToSeekDoctor: string;
  };
  disclaimer: string;
};

type ChatMessage = {
  id: string;
  role: "bot" | "user";
  text: string;
};

export default function PatientChatbot() {
  const [open, setOpen] = useState(false);
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);
  const [width, setWidth] = useState(420);
  const [height, setHeight] = useState(600);
  const [isResizing, setIsResizing] = useState(false);
  const resizeRef = useRef({ startX: 0, startY: 0, startWidth: 0, startHeight: 0 });
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const [messages, setMessages] = useState<ChatMessage[]>([
    {
      id: "welcome",
      role: "bot",
      text: "Hello! 👋 I'm your Health Assistant. Tell me about any health concern or disease, and I'll provide helpful domestic remedies and guidance based on your medical history.",
    },
  ]);

  const canSend = useMemo(() => input.trim().length > 0 && !loading, [input, loading]);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  const pushBotMessage = (text: string) => {
    setMessages((prev) => [
      ...prev,
      {
        id: `${Date.now()}-bot`,
        role: "bot",
        text,
      },
    ]);
    setTimeout(scrollToBottom, 100);
  };

  const handleSend = async () => {
    const disease = input.trim();
    if (!disease || loading) return;

    const user = JSON.parse(localStorage.getItem("user") || "{}");

    if (!user?.patientId) {
      pushBotMessage("I could not find your patient profile. Please login again.");
      return;
    }

    setMessages((prev) => [
      ...prev,
      {
        id: `${Date.now()}-user`,
        role: "user",
        text: disease,
      },
    ]);

    setInput("");
    setLoading(true);
    setTimeout(scrollToBottom, 50);

    try {
      const response = await fetch(
        `http://localhost:5000/api/patient/${user.patientId}/chatbot/guidance`,
        {
          method: "POST",
          headers: {
            "Content-Type": "application/json",
            Authorization: `Bearer ${localStorage.getItem("token")}`,
          },
          body: JSON.stringify({ disease }),
        }
      );

      const data = (await response.json()) as GuidanceResponse | { message?: string };

      if (!response.ok) {
        throw new Error(
          (data as { message?: string })?.message ||
            "Failed to get guidance from assistant"
        );
      }

      const payload = data as GuidanceResponse;

      const reply = [
        `🏥 **Disease:** ${payload.disease}`,
        "",
        `💊 **Your Latest Prescription:**`,
        payload.prescription,
        "",
        `📝 **AI Summary:**`,
        payload.llmGuidance.summary,
        "",
        `🏡 **Domestic Remedies:**`,
        ...payload.llmGuidance.domesticRemedies.map((item, i) => `${i + 1}. ${item}`),
        "",
        `⚠️ **Precautions:**`,
        ...payload.llmGuidance.precautions.map((item, i) => `${i + 1}. ${item}`),
        "",
        `🚑 **When to seek doctor:**`,
        payload.llmGuidance.whenToSeekDoctor,
        "",
        `📋 ${payload.disclaimer}`,
      ].join("\n");

      pushBotMessage(reply);
    } catch (error: any) {
      pushBotMessage(
        `❌ Error: ${
          error?.message ||
          "Something went wrong while contacting the AI assistant."
        }`
      );
    } finally {
      setLoading(false);
    }
  };

  const handleMouseDownResize = (e: React.MouseEvent) => {
    e.preventDefault();
    setIsResizing(true);
    resizeRef.current = {
      startX: e.clientX,
      startY: e.clientY,
      startWidth: width,
      startHeight: height,
    };
  };

  const handleMouseMove = (e: MouseEvent) => {
    if (!isResizing) return;

    const deltaX = e.clientX - resizeRef.current.startX;
    const deltaY = e.clientY - resizeRef.current.startY;

    const newWidth = Math.max(320, resizeRef.current.startWidth + deltaX);
    const newHeight = Math.max(400, resizeRef.current.startHeight + deltaY);

    setWidth(newWidth);
    setHeight(newHeight);
  };

  const handleMouseUpResize = () => {
    setIsResizing(false);
  };

  // Attach mouse move listener when resizing
  if (typeof window !== "undefined") {
    if (isResizing) {
      window.addEventListener("mousemove", handleMouseMove);
      window.addEventListener("mouseup", handleMouseUpResize);
    }
    return () => {
      window.removeEventListener("mousemove", handleMouseMove);
      window.removeEventListener("mouseup", handleMouseUpResize);
    };
  }

  return (
    <>
      {/* Floating Button */}
      <button
        type="button"
        onClick={() => setOpen((prev) => !prev)}
        className={`fixed bottom-6 right-6 z-50 h-16 w-16 rounded-full shadow-2xl transition-all duration-300 flex items-center justify-center font-semibold text-white ${
          open
            ? "bg-linear-to-r from-emerald-500 to-emerald-600 scale-95"
            : "bg-linear-to-r from-emerald-500 to-emerald-600 hover:shadow-emerald-500/50 hover:scale-105"
        }`}
        aria-label="Open patient chatbot"
      >
        {open ? (
          <X className="h-7 w-7" />
        ) : (
          <MessageCircle className="h-7 w-7" />
        )}
      </button>

      {/* Chat Window */}
      {open && (
        <div
          className="fixed z-50 rounded-2xl border border-white/10 bg-white dark:bg-slate-950 shadow-2xl flex flex-col overflow-hidden"
          style={{
            width: `${width}px`,
            height: `${height}px`,
            bottom: "120px",
            right: "24px",
          }}
        >
          {/* Header */}
          <div className="bg-linear-to-r from-emerald-500 to-emerald-600 text-white px-5 py-4 flex items-center justify-between shrink-0">
            <div className="flex items-center gap-3">
              <div className="w-10 h-10 rounded-full bg-white/20 flex items-center justify-center">
                <MessageCircle className="h-6 w-6 text-white" />
              </div>
              <div>
                <h3 className="font-semibold text-sm">Health Assistant</h3>
                <p className="text-xs text-emerald-100">AI-Powered Guidance</p>
              </div>
            </div>
            <button
              onClick={() => setOpen(false)}
              className="text-white/70 hover:text-white transition-colors"
            >
              <X className="h-5 w-5" />
            </button>
          </div>

          {/* Messages Area */}
          <div className="flex-1 overflow-y-auto px-4 py-4 space-y-3 bg-slate-50 dark:bg-slate-900/50">
            {messages.map((message) => (
              <div
                key={message.id}
                className={`flex ${message.role === "user" ? "justify-end" : "justify-start"}`}
              >
                <div
                  className={`max-w-xs px-4 py-3 rounded-2xl text-sm whitespace-pre-wrap leading-relaxed ${
                    message.role === "user"
                      ? "bg-emerald-500 text-white rounded-br-none shadow-md"
                      : "bg-white dark:bg-slate-800 text-slate-900 dark:text-slate-100 border border-slate-200 dark:border-slate-700 rounded-bl-none shadow-sm"
                  }`}
                >
                  {message.text}
                </div>
              </div>
            ))}

            {loading && (
              <div className="flex justify-start">
                <div className="bg-white dark:bg-slate-800 text-slate-900 dark:text-slate-100 border border-slate-200 dark:border-slate-700 px-4 py-3 rounded-2xl rounded-bl-none">
                  <div className="flex gap-1">
                    <div className="w-2 h-2 bg-emerald-500 rounded-full animate-bounce"></div>
                    <div
                      className="w-2 h-2 bg-emerald-500 rounded-full animate-bounce"
                      style={{ animationDelay: "0.1s" }}
                    ></div>
                    <div
                      className="w-2 h-2 bg-emerald-500 rounded-full animate-bounce"
                      style={{ animationDelay: "0.2s" }}
                    ></div>
                  </div>
                </div>
              </div>
            )}

            <div ref={messagesEndRef} />
          </div>

          {/* Input Area */}
          <div className="border-t border-slate-200 dark:border-slate-700 px-4 py-3 bg-white dark:bg-slate-900 shrink-0">
            <div className="flex gap-2 items-center">
              <input
                type="text"
                value={input}
                onChange={(event) => setInput(event.target.value)}
                onKeyDown={(event) => {
                  if (event.key === "Enter" && !event.shiftKey) {
                    event.preventDefault();
                    handleSend();
                  }
                }}
                placeholder="Ask about any disease..."
                className="flex-1 rounded-full bg-slate-100 dark:bg-slate-800 border border-slate-300 dark:border-slate-600 px-4 py-2.5 text-sm text-slate-900 dark:text-white placeholder:text-slate-500 dark:placeholder:text-slate-400 outline-none focus:border-emerald-400 dark:focus:border-emerald-500 transition-colors"
              />
              <button
                type="button"
                onClick={handleSend}
                disabled={!canSend}
                className="h-10 w-10 rounded-full bg-emerald-500 hover:bg-emerald-600 text-white disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center transition-colors"
                aria-label="Send message"
              >
                <Send className="h-5 w-5" />
              </button>
            </div>
          </div>

          {/* Resize Handle */}
          <div
            onMouseDown={handleMouseDownResize}
            className={`absolute bottom-0 right-0 w-5 h-5 cursor-nwse-resize ${
              isResizing ? "bg-emerald-500/30" : "hover:bg-emerald-500/20"
            } rounded-tl-lg transition-colors`}
            title="Drag to resize"
          >
            <div className="absolute bottom-1 right-1 w-3 h-3 border-r-2 border-b-2 border-emerald-500 opacity-50"></div>
          </div>
        </div>
      )}
    </>
  );
}
